// ═══════════════════════════════════════════════════════════════════════════
// THROWAWAY UI PROTOTYPE — delete me once the prediction display is chosen.
//
// Question: how should the match prediction LOOK under a match tile in the
// schedule? Three structurally different treatments, switchable via the
// floating bar (tap arrows or ← / →):
//
//   A — Inline line      : one compact text row beneath the tile
//   B — Probability bar  : a tug-of-war bar split by win %
//   C — Detail card      : scores + % + a little distribution curve
//
// The numbers are REAL — generated by prediction_model.dart (the keeper) from
// mock team stats — so what you see is what the model actually produces. Right
// now we're only judging the visual; the model itself comes next.
//
// Run it (its own entrypoint, separate from the app):
//   flutter run -t lib/prototype/prediction_ui_prototype.dart -d <device-id>
// ═══════════════════════════════════════════════════════════════════════════

import 'dart:math' as math;

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

import '../core/theme/app_theme.dart';
import 'prediction_model.dart';

void main() => runApp(const _PrototypeApp());

class _PrototypeApp extends StatelessWidget {
  const _PrototypeApp();

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Prediction UI Prototype',
      debugShowCheckedModeBanner: false,
      theme: AppTheme.light,
      darkTheme: AppTheme.dark,
      themeMode: ThemeMode.system,
      home: const _Shell(),
    );
  }
}

// ── mock data (numbers are real, fed through prediction_model) ───────────────

const int _myTeam = 751;

final Map<int, TeamStat> _roster = {
  254: const TeamStat(254, 15.0, 2.4),
  1678: const TeamStat(1678, 12.9, 1.9),
  118: const TeamStat(118, 12.5, 3.1),
  751: const TeamStat(751, 11.3, 2.2),
  4414: const TeamStat(4414, 8.3, 2.6),
  2056: const TeamStat(2056, 4.4, 1.3),
  9999: const TeamStat(9999, 1.7, 0.9),
};

double get _leagueMean {
  final s = _roster.values.where((t) => t.scouted);
  return s.map((t) => t.mean!).reduce((a, b) => a + b) / s.length;
}

double get _leagueStd {
  final s = _roster.values.where((t) => t.scouted);
  return s.map((t) => t.std!).reduce((a, b) => a + b) / s.length;
}

class _Match {
  const _Match(this.label, this.red, this.blue);
  final String label;
  final List<int> red;
  final List<int> blue;
}

const List<_Match> _matches = [
  _Match('Qual 12', [751, 1678, 9999], [2056, 4414, 118]), // us red, favored
  _Match('Qual 15', [254, 9999, 2056], [751, 4414, 1678]), // us blue, close
  _Match('Qual 18', [751, 118, 6321], [254, 4414, 2056]), // 6321 unscouted
];

List<TeamStat> _teamsOf(List<int> nums) =>
    nums.map((n) => _roster[n] ?? TeamStat(n, null, null)).toList();

MatchP _predict(_Match m) => predictMatch(
      _teamsOf(m.red),
      _teamsOf(m.blue),
      policy: MissingPolicy.leagueAverage,
      leagueMean: _leagueMean,
      leagueStd: _leagueStd,
    );

// ── shell + switcher (same pattern as the analytics prototype) ──────────────

class _Shell extends StatefulWidget {
  const _Shell();

  @override
  State<_Shell> createState() => _ShellState();
}

class _ShellState extends State<_Shell> {
  static const _names = ['Inline line', 'Probability bar', 'Detail card'];
  int _variant = 0;

  void _cycle(int d) => setState(() => _variant = (_variant + d) % _names.length);

  KeyEventResult _onKey(FocusNode _, KeyEvent e) {
    if (e is! KeyDownEvent) return KeyEventResult.ignored;
    if (e.logicalKey == LogicalKeyboardKey.arrowRight) {
      _cycle(1);
      return KeyEventResult.handled;
    }
    if (e.logicalKey == LogicalKeyboardKey.arrowLeft) {
      _cycle(-1);
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  @override
  Widget build(BuildContext context) {
    return Focus(
      autofocus: true,
      onKeyEvent: _onKey,
      child: Stack(
        children: [
          Scaffold(
            appBar: AppBar(title: const Text('751 @ Contra Costa')),
            body: ListView.separated(
              padding: const EdgeInsets.only(bottom: 96),
              itemCount: _matches.length,
              separatorBuilder: (_, _) => const Divider(height: 1),
              itemBuilder: (_, i) => _MatchRow(
                match: _matches[i],
                prediction: _predict(_matches[i]),
                variant: _variant,
              ),
            ),
          ),
          Positioned(
            left: 0,
            right: 0,
            bottom: 24,
            child: Center(
              child: _SwitcherPill(
                label:
                    '${String.fromCharCode(65 + _variant)} — ${_names[_variant]}',
                onPrev: () => _cycle(-1),
                onNext: () => _cycle(1),
              ),
            ),
          ),
        ],
      ),
    );
  }
}

class _SwitcherPill extends StatelessWidget {
  const _SwitcherPill({
    required this.label,
    required this.onPrev,
    required this.onNext,
  });

  final String label;
  final VoidCallback onPrev;
  final VoidCallback onNext;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    return Material(
      color: cs.inverseSurface,
      borderRadius: BorderRadius.circular(28),
      elevation: 6,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 4),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            IconButton(
              onPressed: onPrev,
              icon: const Icon(Icons.chevron_left),
              color: cs.onInverseSurface,
            ),
            Text(label,
                style: TextStyle(
                    color: cs.onInverseSurface, fontWeight: FontWeight.w600)),
            IconButton(
              onPressed: onNext,
              icon: const Icon(Icons.chevron_right),
              color: cs.onInverseSurface,
            ),
          ],
        ),
      ),
    );
  }
}

// ── one schedule row: real-looking match tile + a prediction variant ────────

class _MatchRow extends StatelessWidget {
  const _MatchRow({
    required this.match,
    required this.prediction,
    required this.variant,
  });

  final _Match match;
  final MatchP prediction;
  final int variant;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final isRed = match.red.contains(_myTeam);
    final allianceColor = isRed ? Colors.red.shade700 : Colors.blue.shade700;
    final partners =
        (isRed ? match.red : match.blue).where((t) => t != _myTeam).join(' · ');
    final opponents = (isRed ? match.blue : match.red).join(' · ');

    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        ListTile(
          leading: Container(width: 4, height: 40, color: allianceColor),
          contentPadding:
              const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
          title: Text(match.label,
              style: const TextStyle(fontWeight: FontWeight.w600)),
          subtitle: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text('Partners: $partners'),
              Text('Vs: $opponents',
                  style: TextStyle(color: cs.onSurfaceVariant)),
            ],
          ),
        ),
        switch (variant) {
          0 => _InlineLine(prediction),
          1 => _ProbabilityBar(prediction),
          _ => _DetailCard(prediction),
        },
      ],
    );
  }
}

// ── VARIANT A — inline text line ────────────────────────────────────────────

class _InlineLine extends StatelessWidget {
  const _InlineLine(this.p);
  final MatchP p;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final rp = (p.redWinPct * 100).round();
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
      child: Column(
        children: [
          Row(
            children: [
              Text('🔴 ${p.red.expected.round()} pts · $rp%',
                  style: TextStyle(
                      color: Colors.red.shade700,
                      fontWeight: FontWeight.w600,
                      fontSize: 13)),
              const Spacer(),
              Text('${100 - rp}% · ${p.blue.expected.round()} pts 🔵',
                  style: TextStyle(
                      color: Colors.blue.shade700,
                      fontWeight: FontWeight.w600,
                      fontSize: 13)),
            ],
          ),
          if (p.scoutedCount < 6)
            Padding(
              padding: const EdgeInsets.only(top: 2),
              child: Text('${p.scoutedCount}/6 teams scouted',
                  style: TextStyle(
                      fontSize: 10,
                      fontStyle: FontStyle.italic,
                      color: cs.onSurfaceVariant)),
            ),
        ],
      ),
    );
  }
}

// ── VARIANT B — tug-of-war probability bar ──────────────────────────────────

class _ProbabilityBar extends StatelessWidget {
  const _ProbabilityBar(this.p);
  final MatchP p;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final rp = (p.redWinPct * 100).round();
    final rFlex = (p.redWinPct * 1000).round().clamp(0, 1000);

    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
      child: Column(
        children: [
          Row(
            children: [
              SizedBox(
                width: 28,
                child: Text('${p.red.expected.round()}',
                    style: TextStyle(
                        color: Colors.red.shade700,
                        fontWeight: FontWeight.bold)),
              ),
              Expanded(
                child: ClipRRect(
                  borderRadius: BorderRadius.circular(6),
                  child: Row(
                    children: [
                      if (rFlex > 0)
                        Expanded(
                          flex: rFlex,
                          child: Container(
                            height: 24,
                            color: Colors.red.shade600,
                            alignment: Alignment.centerLeft,
                            padding: const EdgeInsets.symmetric(horizontal: 6),
                            child: Text('$rp%',
                                style: const TextStyle(
                                    color: Colors.white,
                                    fontSize: 11,
                                    fontWeight: FontWeight.bold)),
                          ),
                        ),
                      if (rFlex < 1000)
                        Expanded(
                          flex: 1000 - rFlex,
                          child: Container(
                            height: 24,
                            color: Colors.blue.shade600,
                            alignment: Alignment.centerRight,
                            padding: const EdgeInsets.symmetric(horizontal: 6),
                            child: Text('${100 - rp}%',
                                style: const TextStyle(
                                    color: Colors.white,
                                    fontSize: 11,
                                    fontWeight: FontWeight.bold)),
                          ),
                        ),
                    ],
                  ),
                ),
              ),
              SizedBox(
                width: 28,
                child: Text('${p.blue.expected.round()}',
                    textAlign: TextAlign.right,
                    style: TextStyle(
                        color: Colors.blue.shade700,
                        fontWeight: FontWeight.bold)),
              ),
            ],
          ),
          if (p.scoutedCount < 6)
            Padding(
              padding: const EdgeInsets.only(top: 4),
              child: Text('${p.scoutedCount}/6 teams scouted',
                  style: TextStyle(
                      fontSize: 10,
                      fontStyle: FontStyle.italic,
                      color: cs.onSurfaceVariant)),
            ),
        ],
      ),
    );
  }
}

// ── VARIANT C — detail card with a distribution curve ───────────────────────

