                children: [
                  Text('${p.red.expected.round()}',
                      style: TextStyle(
                          fontSize: 30,
                          fontWeight: FontWeight.bold,
                          color: Colors.red.shade700)),
                  Text('  –  ',
                      style: TextStyle(
                          fontSize: 22, color: cs.onSurfaceVariant)),
