    );
  }
}

/// Two unnormalised Gaussians (peak height 1) — shows each alliance's score
/// spread and how much they overlap. Pure shape, not to scale.
class _CurvePainter extends CustomPainter {
  _CurvePainter({
    required this.redMu,
    required this.redSigma,
    required this.blueMu,
    required this.blueSigma,
    required this.redColor,
    required this.blueColor,
  });

  final double redMu, redSigma, blueMu, blueSigma;
  final Color redColor, blueColor;

  @override
  void paint(Canvas canvas, Size size) {
    final maxSigma = [redSigma, blueSigma, 1.0].reduce(math.max);
    final lo = math.min(redMu, blueMu) - 3 * maxSigma;
    final hi = math.max(redMu, blueMu) + 3 * maxSigma;
    final span = (hi - lo).clamp(1.0, double.infinity);

    Path pathFor(double mu, double sigma) {
      final s = math.max(sigma, 0.5);
      final path = Path();
      const samples = 80;
      for (var i = 0; i <= samples; i++) {
        final x = lo + span * i / samples;
        final z = (x - mu) / s;
        final y = math.exp(-0.5 * z * z); // peak 1
        final px = size.width * i / samples;
        final py = size.height - y * size.height * 0.9;
        if (i == 0) {
          path.moveTo(px, py);
        } else {
          path.lineTo(px, py);
        }
      }
      return path;
    }

    void draw(double mu, double sigma, Color color) {
      final line = pathFor(mu, sigma);
      final fill = Path.from(line)
        ..lineTo(size.width, size.height)
        ..lineTo(0, size.height)
        ..close();
      canvas.drawPath(
          fill, Paint()..color = color.withValues(alpha: 0.15));
      canvas.drawPath(
          line,
          Paint()
            ..color = color
            ..style = PaintingStyle.stroke
            ..strokeWidth = 2);
    }

    draw(blueMu, blueSigma, blueColor);
    draw(redMu, redSigma, redColor);
  }

  @override
  bool shouldRepaint(_CurvePainter old) =>
      old.redMu != redMu ||
      old.blueMu != blueMu ||
      old.redSigma != redSigma ||
      old.blueSigma != blueSigma;
}
